labs.cli:
aws s3api create-bucket --bucket my-saa-lab-bucket --region eu-west-1 --create-bucket-configuration LocationConstraint=eu-west-1

aws s3api put-bucket-versioning --bucket my-saa-lab-bucket --versioning-configuration Status=Enabled

aws s3api put-bucket-lifecycle-configuration --bucket my-saa-lab-bucket --lifecycle-configuration '{
  "Rules": [{
    "ID": "archive-then-expire",
    "Status": "Enabled",
    "Filter": {"Prefix": ""},
    "Transitions": [
      {"Days": 30, "StorageClass": "STANDARD_IA"},
      {"Days": 90, "StorageClass": "GLACIER"}
    ],
    "NoncurrentVersionExpiration": {"NoncurrentDays": 60},
    "AbortIncompleteMultipartUpload": {"DaysAfterInitiation": 7}
  }]
}'

aws s3api put-bucket-encryption --bucket my-saa-lab-bucket --server-side-encryption-configuration '{
  "Rules": [{
    "ApplyServerSideEncryptionByDefault": {
      "SSEAlgorithm": "aws:kms",
      "KMSMasterKeyID": "alias/aws/s3"
    },
    "BucketKeyEnabled": true
  }]
}'

aws s3api put-public-access-block --bucket my-saa-lab-bucket --public-access-block-configuration BlockPublicAcls=true,IgnorePublicAcls=true,BlockPublicPolicy=true,RestrictPublicBuckets=true

labs.pulumi:
import pulumi_aws as aws

aws.s3.BucketServerSideEncryptionConfigurationV2(
    "saa-lab-sse",
    bucket="my-saa-lab-bucket",
    rules=[{
        "apply_server_side_encryption_by_default": {
            "sse_algorithm": "aws:kms",
            "kms_master_key_id": "alias/aws/s3",
        },
        "bucket_key_enabled": True,
    }],
)

aws.s3.BucketPublicAccessBlock(
    "saa-lab-bpa",
    bucket="my-saa-lab-bucket",
    block_public_acls=True,
    ignore_public_acls=True,
    block_public_policy=True,
    restrict_public_buckets=True,
)
